var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"흑, 흐윽. 그렇지만…… 왜 하필 내 아들이……! 내 아들이!!","JPN":"うっ、ううっ。でも……なんで私の息子が……！　私の息子が！！","ENG":"*Sob* *Sob* B-but... my son...! My son...!","TWN":"嗚，嗚嗚，可是……為什麼偏偏是我的兒子……！我的兒子！！"},"stage":{"bg":"CORRIDOR_05","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"미안하데이. 박스…… 아니 철수야.","JPN":"ごめんな。ダンボール……いや、ジロウ。","ENG":"I’m sorry, Box... I mean, Chulsoo.","TWN":"對不起，紙箱……不對，是哲洙。"},"stage":{"bg":"CORRIDOR_05","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내 잘못이다. 내가 철수를 데꼬왔기 때문에 이렇게…….","JPN":"ウチのせいや。ウチがジロウを連れてきたせいで、こんなん……","ENG":"It's all my fault. I brought Chulsoo here, but...","TWN":"都怪我不好，都是因為我把哲洙帶來，才會……"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"사람들을 지키기 위해 카운터가 된 긴데, 정작 소중한 동생도 못 지키고…….","JPN":"みんなを守るためにカウンターになったのに、大切な人も守られへんかった……","ENG":"I became a Counter to protect people. But I couldn't even save the person important to me...","TWN":"我是因為想保護人才成為制裁者的，結果我卻連弟弟都保護不了……"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"흑흑…… 나 때문에…….","JPN":"ううっ……ウチのせいで……","ENG":"*Sob* It's all my fault...","TWN":"嗚嗚……都怪我……"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"타임 캡슐도, 후속작도…… 이럴 거면 말도 안 하는 게 좋았을 긴데…….","JPN":"タイムカプセルも、続編も……こうなるんやったら何も言わん方がよかった……","ENG":"The time capsule, or even the sequel... I shouldn't have mentioned them if I knew this was going to happen...","TWN":"什麼時空膠囊、續作…… 早知道會這樣，根本就不應該提……"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……리네만의 잘못이 아니잖아. 우리 모두의 잘못이야.","JPN":"……マリちゃんだけが悪いわけじゃないよ。私たちみんなが悪いの。","ENG":"...It's not just your fault, Rinae. It's ours.","TWN":"……這不能都怪你，我們也有錯。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"철수는 무사하니까…… 언젠가 다시 만날 수 있을 거야.","JPN":"ジロウは無事だから……いつかまた会えるはずよ。","ENG":"Chulsoo is safe, so... we'll see him again one day.","TWN":"至少哲洙人沒事……總有一天我們會再相見的。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하지만…… 철수가 기억을 되찾는다 해도 우릴 보고 싶어 하지 않을기다.","JPN":"せやけど……ジロウが記憶を取り戻しても、ウチらに会いたいとは思わないはずや。","ENG":"But... Even if he regains his memories, he won't want to see us again.","TWN":"可是……就算哲洙找回記憶，可能也未必想見我們。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……아냐.","JPN":"……違う。","ENG":"…No.","TWN":"……不會的。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응……?","JPN":"うん……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"철수는…… 강해.","JPN":"ジロウは……強い。","ENG":"Chulsoo... is strong.","TWN":"哲洙……很堅強。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"죽을 수도 있었는데……. 우릴 구하기 위해 달려왔잖아.","JPN":"死ぬかもしれないのに……私たちを助けるために駆けつけてきた。","ENG":"He knew he could die, but... he came to save us anyway.","TWN":"明知道可能會死……還是跑來救我們。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"보라 말이 맞아. 여기서 끝나면, 철수도 받아들이지 못할 거야.","JPN":"シホちゃんの言うとおりよ。ここで終わったら、ジロウも受け入れられないわ。","ENG":"Bora's right. If we end it here, Chulsoo will get mad at us.","TWN":"寶拉說的沒錯，我們就在這裡結束的話，哲洙也不會原諒我們的。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"리네도…… 이렇게 끝내고 싶지 않잖아?","JPN":"マリちゃんも……こんな風に終わらせたくないでしょう？","ENG":"And even you... don't want it to end right now, right, Rinae?","TWN":"璃奈……你也不希望就這樣結束吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"기다려주자……. 철수가 회복할 때까지.","JPN":"待とう……ジロウが回復するまで。","ENG":"Let's wait for him... Until he gets better.","TWN":"等吧……等到哲洙恢復過來。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그때까지 우리…… 모두 어엿한 어른이 되어 있는 거야.","JPN":"その時までに私たち……みんな立派な大人になる。","ENG":"By then... we'll all be respectable adults.","TWN":"在那之前，我們……都要成為堂堂正正的大人。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그리고…… 다시 만나러 가는 거야……. 셋이서.","JPN":"そして……また会いに行く……3人で。","ENG":"And... we'll go see him again... The three of us.","TWN":"然後……再去見他……三個一起。"},"stage":{"bg":"CIRCLEROOM","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};